import { useEffect, useState } from "react";
import { analyzeAudio, DTW, transcribeAudio } from "../services/api";

type PitchPoint = {
  time: number;
  frequency: number;
};

export function useAudioAnalysisReference(
  referenceBlob: Blob | null,
  chosenAudio: string
) {
  const [referencePitch, setReferencePitch] = useState<PitchPoint[]>([]);

  useEffect(() => {
    const analyzeReference = async () => {
      if (!referenceBlob) return;
      const data = await analyzeAudio(referenceBlob, chosenAudio);
      if (
        data &&
        JSON.stringify(data.pitch) !== JSON.stringify(referencePitch)
      ) {
        setReferencePitch(data.pitch);
      }
    };
    analyzeReference();
  }, [referenceBlob, chosenAudio]);

  const clearReferencePitch = () => {
    setReferencePitch([]);
  };

  return { referencePitch, clearReferencePitch };
}

export function useAudioAnalysisUser(
  userBlob: Blob | null,
  chosenAudio: string,
  referencePitch: PitchPoint[],
  currentPhrase: string,
  test: string | null,
  currentIndex: string
) {
  const [userPitch, setUserPitch] = useState<PitchPoint[]>([]);
  const [userWordsArray, setUserWordsArray] = useState<any[]>([]);
  const [alignedGraphData, setAlignedGraphData] = useState<any[]>([]);
  const [accuracy, setAccuracy] = useState(0);
  const [refWordsArray, setRefWordsArray] = useState<any[]>([]);

  useEffect(() => {
    const analyzeUser = async () => {
      const data = await analyzeAudio(userBlob, "recording" + chosenAudio);
      if (data) {
        setUserPitch(data.pitch);

        if (referencePitch.length > 0) {
          const user_chars_array = await transcribeAudio(
            userBlob,
            "recording" + chosenAudio,
            currentPhrase
          );
          setUserWordsArray(user_chars_array);

          console.log("✅ User Character Segments:", user_chars_array);
          const [aligned_graph_data, total_accuracy, ref_characters] =
            await DTW(
              data.pitch,
              referencePitch,
              test,
              user_chars_array,
              currentIndex
            );
          setAlignedGraphData(aligned_graph_data);
          setAccuracy(total_accuracy);
          setRefWordsArray(ref_characters);
        }
      }
    };

    if (userBlob) {
      analyzeUser();
    }
  }, [userBlob, chosenAudio]);

  const clearPitch = () => {
    setUserPitch([]);
    setAlignedGraphData([]);
  };

  return {
    userPitch,
    userWordsArray,
    refWordsArray,
    alignedGraphData,
    clearPitch,
    accuracy,
  };
}
